 1	import * as React from 'react';
 2	import { MenuToggle, Popper } from '@patternfly/react-core';
 3	import { default as classNames } from 'classnames';
 4	
 5	const ProjectMenuToggle = (props: {
 6	  disabled: boolean;
 7	  menu: React.ReactElement;
 8	  menuRef: React.RefObject<HTMLElement>;
 9	  isOpen: boolean;
10	  shortCut?: string;
11	  title: string;
12	  onToggle: (state: boolean) => void;
13	  className?: string;
14	}) => {
15	  const { menu, isOpen, shortCut, title, onToggle, disabled, menuRef, className } = props;
16	
17	  const toggleRef = React.useRef(null);
18	  const containerRef = React.useRef(null);
19	
20	  const handleMenuKeys = (event) => {
21	    if (
22	      shortCut &&
23	      event.key === shortCut &&
24	      event.target.nodeName !== 'INPUT' &&
25	      event.target.nodeName !== 'TEXTAREA' &&
26	      event.target.role !== 'textbox' &&
27	      event.target.role !== 'code'
28	    ) {
29	      onToggle(true);
30	      event.stopPropagation();
31	      event.preventDefault();
32	    }
33	
34	    if (menuRef.current) {
35	      if (event.key === 'Escape') {
36	        onToggle(false);
37	        toggleRef.current.focus();
38	      }
39	      if (!menuRef.current?.contains(event.target) && event.key === 'Tab') {
40	        onToggle(false);
41	      }
42	    }
43	  };
44	
45	  const handleMenuClick = (event) => {
46	    if (
47	      menuRef.current &&
48	      !menuRef.current?.contains(event.target) &&
49	      // Checking to see if user clicked on a favorite icon.  This is needed because
50	      // if unfavoriting a item, PF removes the item from the DOM before
51	      // the click event is registered
52	      !event.target.closest?.('.pf-m-favorite') &&
53	      !toggleRef.current.contains(event.target)
54	    ) {
55	      onToggle(false);
56	    }
57	  };
58	
59	  React.useEffect(() => {
60	    window.addEventListener('keyup', handleMenuKeys);
61	    window.addEventListener('click', handleMenuClick);
62	    return () => {
63	      window.removeEventListener('keyup', handleMenuKeys);
64	      window.removeEventListener('click', handleMenuClick);
65	    };
66	    // eslint-disable-next-line react-hooks/exhaustive-deps
67	  }, []); // This needs to be run only on component mount/unmount
68	
69	  const toggle = (
70	    <MenuToggle
71	      ref={toggleRef}
72	      onClick={() => onToggle(!isOpen)}
73	      isExpanded={isOpen}
74	      disabled={disabled}
75	      className={classNames('monitoring__project-dropdown__menu-toggle', className)}
76	    >
77	      {title}
78	    </MenuToggle>
79	  );
80	
81	  return (
82	    <div ref={containerRef}>
83	      <Popper
84	        trigger={toggle}
85	        popper={menu}
86	        direction="down"
87	        position="left"
88	        appendTo={containerRef.current}
89	        isVisible={isOpen}
90	        enableFlip={false}
91	      />
92	    </div>
93	  );
94	};
95	
96	export default ProjectMenuToggle;

